package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.lang.reflect.Method;

import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.eclipse.rdf4j.sail.lmdb.evaluation.LmdbNativeAttemptMetrics;
import org.eclipse.rdf4j.sail.lmdb.model.LmdbLiteral;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class ValueStoreAdaptiveCacheTest {

	@Test
	void defaultBudgetsScaleFromMaximumHeap() throws Exception {
		long maxHeapBytes = 64L * 1024 * 1024 * 1024;
		Method factory = ValueStore.class.getDeclaredMethod("dictionaryCacheBudgets", long.class);
		factory.setAccessible(true);
		Object budgets = factory.invoke(null, maxHeapBytes);

		assertThat(component(budgets, "valueBytes")).isEqualTo(maxHeapBytes / 64);
		assertThat(component(budgets, "valueIdBytes")).isEqualTo(maxHeapBytes / 256);
		assertThat(component(budgets, "namespaceBytes")).isEqualTo(maxHeapBytes / 1024);
		assertThat(component(budgets, "namespaceIdBytes")).isEqualTo(maxHeapBytes / 1024);
	}

	@Test
	void namespaceDefaultsSurviveRealWorldVocabularies() {
		LmdbStoreConfig config = new LmdbStoreConfig();

		assertThat(config.getNamespaceCacheSize()).isEqualTo(1024);
		assertThat(config.getNamespaceIDCacheSize()).isEqualTo(1024);
	}

	@Test
	void valueCacheHitsAndMissesAreObservable(@TempDir File dataDir) throws Exception {
		ValueStore valueStore = new ValueStore(new File(dataDir, "values"), new LmdbStoreConfig());
		try {
			Object before = dictionaryMetrics();
			LmdbLiteral value = valueStore.createLiteral("cached");
			value.setInternalID(73L, value.getValueStoreRevision());

			assertThat(valueStore.cachedValue(74L)).isNull();
			valueStore.cacheValue(73L, value);
			assertThat(valueStore.cachedValue(73L)).isSameAs(value);

			Object after = dictionaryMetrics();
			assertThat(component(after, "valueHits") - component(before, "valueHits")).isOne();
			assertThat(component(after, "valueMisses") - component(before, "valueMisses")).isOne();
		} finally {
			valueStore.close();
		}
	}

	private static Object dictionaryMetrics() throws Exception {
		Method metrics = LmdbNativeAttemptMetrics.class.getDeclaredMethod("dictionaryCacheMetrics");
		metrics.setAccessible(true);
		return metrics.invoke(null);
	}

	private static long component(Object record, String name) throws Exception {
		Method accessor = record.getClass().getDeclaredMethod(name);
		accessor.setAccessible(true);
		return ((Number) accessor.invoke(record)).longValue();
	}
}
